# coding: utf-8


class RainbowException(Exception):
    def __str__(self) -> str:
        return super().__str__()


class NoConfigException(RainbowException):
    def __init__(self, config_name, *args: object) -> None:
        super().__init__(config_name, *args)
        self.config_name = config_name

    def __str__(self) -> str:
        return f"没有此配置：{self.config_name}"


class Timeout(RainbowException):
    def __str__(self) -> str:
        return "请求超时"


class HTTPException(RainbowException):
    def __init__(self, *args: object) -> None:
        super().__init__(*args)
        self.e = args[0]

    def __str__(self) -> str:
        return "请求失败：" + str(self.e)


class DecodeException(RainbowException):
    def __init__(self, *args: object) -> None:
        super().__init__(*args)
        self.response = args[0]

    def __str__(self) -> str:
        return "json 解析失败：" + self.response.text


class ResponseException(RainbowException):
    def __init__(self, code, reason, response_json, *args: object) -> None:
        super().__init__(*args)
        self.response_json = response_json
        self.reason = reason
        self.code = code

    def __str__(self) -> str:
        return f"response 错误：{self.code}: {self.reason}\n{self.response_json}"


class CL5Exception(RainbowException):
    pass
